#include <stdio.h>
#include <math.h>

int main() {
  // Define camera parameters
  double focal_length = 50;  // mm
  double diameter = 25;  // mm
  double theta = M_PI / 4;  // radians

  // Define scene radiance
  double scene_radiance = 100;  // W/m^2

  // Calculate image irradiance
  double image_irradiance = scene_radiance * (M_PI / 4) * pow(diameter / focal_length, 2) * pow(cos(theta), 4);

  // Apply camera response function (simple gamma correction)
  double pixel_values = pow(image_irradiance, 2.2);

  // Perform spatial sampling and quantization (simple 8-bit quantization)
  unsigned char digital_image = round(pixel_values * 255);

  printf("%u\n", digital_image);

  return 0;
}
